import{G as a,c as o,b as r,ae as t}from"./chunks/framework.Cpb2nuHT.js";const b=JSON.parse('{"title":"Java并发的happens-before规则","description":"","frontmatter":{"title":"Java并发的happens-before规则","date":"2024/7/29","tags":["Java","并发","多线程"],"author":"花木凋零成兰"},"headers":[],"relativePath":"MisNotes/Java并发的happens-before规则.md","filePath":"MisNotes/Java并发的happens-before规则.md","lastUpdated":1722516194000}'),s={name:"MisNotes/Java并发的happens-before规则.md"};function n(p,e,i,l,h,f){return r(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1722211200000"},[...e[0]||(e[0]=[t('<h1 id="java并发的happens-before规则" tabindex="-1">Java并发的happens-before规则 <a class="header-anchor" href="#java并发的happens-before规则" aria-label="Permalink to &quot;Java并发的happens-before规则&quot;">​</a></h1><h2 id="happens-before规则" tabindex="-1">happens-before规则 <a class="header-anchor" href="#happens-before规则" aria-label="Permalink to &quot;happens-before规则&quot;">​</a></h2><ol><li><strong>程序次序规则：</strong> 同一个线程内一段代码的执行顺序是有序的, 即前面的操作 happens-before 后面的操作; 但还是有可能发生指令重排序, 不过重排序后的结果与顺序执行的结果一致;</li><li><strong>管程锁定规则：</strong> 对一个锁的解锁操作 happens-before 后续对这个锁的加锁操作; 即后续的加锁操作能够感知到前面解锁的变化, <code>synchronized</code> 就是管程的实现;</li><li><strong>volatile 变量规则：</strong> 对 <code>valatile</code> 修饰的变量的更新操作 happens-before 后续对此变量的任意操作; (可以了解内存屏障和缓存一致性协议)</li><li><strong>传递性规则：</strong> A happens-before B, B happens-before C, 则 A happens-before C; 即关系具有传递行;</li><li><strong>线程启动规则：</strong> 在主线程启动子线程, 那么主线程启动子线程之前的操作对于子线程是可见的; 即 <code>start()</code> happens-before 子线程中的操作;</li><li><strong>线程终止规则：</strong> 在主线程执行过程中, 子线程终止, 那么子线程终止之前的操作在主线程中是可见的; 例如主线程中执行子线程的 join 方法等待子线程完成, 当子线程执行完毕后, 主线程可以看到子线程的所有操作;</li><li><strong>线程中断规则：</strong> 对线程 interrupt 方法的调用 happens-before 被中断线程代码检测到中断事件;</li><li><strong>对象终结规则：</strong> 一个对象的构造函数执行的结束 happens-before 它的 finalize() 方法;</li></ol><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://blog.51cto.com/u_11812862/3002287" target="_blank" rel="noreferrer">阿里面试题：Java 并发编程之 happens-before 规则</a></li></ul>',5)])])}const c=a(s,[["render",n]]);export{b as __pageData,c as default};
